sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    // 1. Get the values directly from the server object
    var degreeLevel = current.getValue('u_degree_level'); 
    var obtained = parseFloat(current.getValue('u_obtained_marks')) || 0;
    var total = parseFloat(current.getValue('u_total_marks')) || 0;
    var cgpa = parseFloat(current.getValue('u_cgpa')) || 0;

    var finalPercentage = 0.0;

    // 2. Calculate logic
    if (degreeLevel == 'bachelor_s' || degreeLevel == 'master_s') {
        if (cgpa > 0 && cgpa <= 4.0) {
            finalPercentage = (cgpa / 4.0) * 100;
        }
    } else {
        if (total > 0) {
            finalPercentage = (obtained / total) * 100;
        }
    }

    // 3. Force the value into the database field before saving
    current.setValue('u_percentage', finalPercentage.toFixed(2));

})(current, previous);
